window.WARRANTA_LEGAL = {"en": {"lang": "en", "name": "English", "privacy": {"title": "Privacy Policy", "updated": "Last updated: 16 July 2026", "intro": "Warranta is a privacy-first vault for your receipts, warranties and return windows. It is built so that everything you add stays on your device. This policy explains, in plain language, what data is involved and how it is handled.", "sections": [{"h": "Data we collect", "p": "None. Warranta requires no account and does not collect, transmit, sell, or share your personal data. Your items, photos, documents, prices and notes never leave your device except within your own device backup (see “Storage & backup”)."}, {"h": "On-device processing", "p": "When you scan a receipt or warranty, the text is read and the fields are filled in using Apple’s on-device Vision framework and on-device intelligence. The image and its text are processed entirely on your iPhone and are never uploaded to us or to any third party."}, {"h": "Network use", "p": "The only network activity is with Apple’s App Store, for purchases and subscriptions. If you buy Warranta Pro, an optional registration may send a single anonymous Apple transaction identifier so your subscription can be recognised — it contains no name, email, or item content. Warranta includes no analytics, advertising, or tracking SDKs of any kind, and shows no ads."}, {"h": "Permissions", "p": "Warranta may ask for Camera (to photograph a receipt or warranty), Photo Library (to pick an existing image), and Notifications (to remind you before a warranty or return window expires). Each permission is optional, requested only when needed, and used solely for the stated purpose."}, {"h": "Storage & backup", "p": "Your data is stored locally on your device. If you have iCloud device backup enabled, your Warranta data is included in that encrypted Apple backup under your own Apple account. We operate no servers that hold your content, and we cannot see your data."}, {"h": "Your rights & control", "p": "You are always in control. You can edit or delete any item inside the app at any time, and deleting the app removes all of its data from your device. Because we do not hold your personal data on any server, there is nothing for us to access, export, correct, or erase on your behalf — rights under the GDPR, UK GDPR, and CCPA/CPRA are satisfied by design."}, {"h": "Third-party services", "p": "The only third party involved is Apple, which processes App Store purchases and subscriptions and provides iCloud backup. Those interactions are governed by Apple’s own Privacy Policy at apple.com/legal/privacy. Warranta integrates no other third-party services, advertising networks, or data brokers."}, {"h": "Data retention", "p": "Your data remains on your device for as long as you keep it and is deleted when you delete it or remove the app. We retain nothing, because we never receive your content in the first place."}, {"h": "International users", "p": "Because all processing happens on your device, your content is not transferred to us or moved across borders. Wherever you use Warranta, your data stays with you."}, {"h": "Children’s privacy", "p": "Warranta is not directed at children under 13 and collects no personal data from anyone, including children."}, {"h": "Changes to this policy", "p": "We may update this policy from time to time. Material changes will be posted on this page with a new “last updated” date; your continued use after an update means you accept the revised policy."}, {"h": "Contact", "p": "Questions about privacy? Email mustafaagulden@gmail.com and we will be glad to help."}]}, "terms": {"title": "Terms of Service", "updated": "Last updated: 16 July 2026", "intro": "These Terms of Service (“Terms”) govern your use of the Warranta app. By downloading or using Warranta, you agree to these Terms. If you do not agree, please do not use the app.", "sections": [{"h": "The service", "p": "Warranta helps you store proof of purchase and keep track of warranty and return windows. It is an organisational tool only: it does not provide, extend, underwrite, or honour any warranty, and its reminders are provided on a best-effort basis and may be delayed or missed for reasons outside our control. Always confirm important dates and terms directly with the seller or manufacturer."}, {"h": "Eligibility", "p": "You may use Warranta only if you can form a binding contract under the law that applies to you, and you are of the age of majority in your country or use the app under the supervision of a parent or legal guardian."}, {"h": "Licence", "p": "We grant you a personal, non-exclusive, non-transferable, revocable licence to use Warranta for your own personal, non-commercial purposes, subject to these Terms and to Apple’s Licensed Application End User Licence Agreement (the standard EULA at apple.com/legal/internet-services/itunes/dev/stdeula)."}, {"h": "Acceptable use", "p": "You agree to use Warranta lawfully and not to resell, rent, or redistribute it, nor to copy, modify, reverse engineer, or attempt to extract its source code except to the limited extent that applicable law expressly permits despite this restriction."}, {"h": "Subscriptions & purchases", "p": "Warranta Pro is offered as auto-renewing subscriptions and, where available, a one-time purchase, all processed by the App Store. Payment is charged to your Apple ID. Subscriptions renew automatically unless cancelled at least 24 hours before the end of the current period. Any free trial converts to a paid subscription unless cancelled before it ends. You can manage or cancel in your App Store account settings. Prices may vary by region and are shown before purchase."}, {"h": "App Store terms", "p": "These Terms are between you and the developer of Warranta, not Apple, and Apple is not responsible for the app or its content. Apple has no obligation to provide any maintenance or support for the app. To the maximum extent permitted by law, Apple has no warranty obligation, and any claims, losses, liabilities, or costs attributable to the app are the developer’s responsibility, not Apple’s. Apple and its subsidiaries are third-party beneficiaries of these Terms and may enforce them against you."}, {"h": "Disclaimer of warranties", "p": "Warranta is provided “as is” and “as available”, without warranties of any kind, whether express or implied. We do not guarantee that reminders will be delivered on time, that scanned data will be accurate, or that the app will be uninterrupted or error-free."}, {"h": "Limitation of liability", "p": "To the maximum extent permitted by law, we are not liable for any missed warranty or return deadline, lost data, or indirect, incidental, special, or consequential damages arising from your use of Warranta. Nothing in these Terms limits or excludes liability that cannot be limited or excluded under the mandatory law of your country."}, {"h": "Intellectual property", "p": "Warranta, its name, design, and content are owned by the developer and protected by applicable intellectual-property law. Your own items, photos, and documents remain entirely yours."}, {"h": "Termination", "p": "This licence continues until terminated. It ends automatically if you breach these Terms in a material way, and you may end it at any time by uninstalling the app. Provisions that by their nature should survive termination — such as disclaimers, limitation of liability, and intellectual-property terms — will continue to apply."}, {"h": "Changes to these terms", "p": "We may update these Terms from time to time. Material changes will be posted on this page with a new “last updated” date. Continued use of Warranta after changes take effect means you accept the updated Terms."}, {"h": "Governing law", "p": "These Terms are governed by the laws of the Republic of Türkiye, without prejudice to any mandatory consumer-protection rights you are entitled to under the law of your country of residence, which continue to apply."}, {"h": "Contact", "p": "Questions about these Terms? Email mustafaagulden@gmail.com."}]}}, "de": {"lang": "de", "name": "Deutsch", "privacy": {"title": "Datenschutzerklärung", "updated": "Zuletzt aktualisiert: 16. Juli 2026", "intro": "Warranta ist ein datenschutzorientierter Tresor für Ihre Belege, Garantien und Rückgabefristen. Es ist so konzipiert, dass alles, was Sie hinzufügen, auf Ihrem Gerät verbleibt. Diese Erklärung beschreibt in verständlicher Sprache, welche Daten betroffen sind und wie sie verarbeitet werden.", "sections": [{"h": "Daten, die wir erheben", "p": "Keine. Warranta erfordert kein Konto und erhebt, überträgt, verkauft oder teilt Ihre personenbezogenen Daten nicht. Ihre Objekte, Fotos, Dokumente, Preise und Notizen verlassen Ihr Gerät niemals, außer im Rahmen Ihrer eigenen Gerätesicherung (siehe „Speicherung & Sicherung“)."}, {"h": "Verarbeitung auf dem Gerät", "p": "Wenn Sie einen Beleg oder eine Garantie scannen, wird der Text mithilfe des geräteinternen Vision-Frameworks von Apple und der geräteinternen Intelligenz ausgelesen und die Felder werden ausgefüllt. Das Bild und sein Text werden vollständig auf Ihrem iPhone verarbeitet und niemals an uns oder an Dritte übertragen."}, {"h": "Netzwerknutzung", "p": "Die einzige Netzwerkaktivität erfolgt mit dem App Store von Apple, für Käufe und Abonnements. Wenn Sie Warranta Pro erwerben, kann eine optionale Registrierung eine einzelne anonyme Apple-Transaktionskennung senden, damit Ihr Abonnement erkannt werden kann — sie enthält keinen Namen, keine E-Mail-Adresse und keine Objektinhalte. Warranta enthält keinerlei Analyse-, Werbe- oder Tracking-SDKs und zeigt keine Werbung an."}, {"h": "Berechtigungen", "p": "Warranta kann um Zugriff auf die Kamera (um einen Beleg oder eine Garantie zu fotografieren), die Fotomediathek (um ein vorhandenes Bild auszuwählen) und Mitteilungen (um Sie vor Ablauf einer Garantie- oder Rückgabefrist zu erinnern) bitten. Jede Berechtigung ist optional, wird nur bei Bedarf angefordert und ausschließlich für den angegebenen Zweck verwendet."}, {"h": "Speicherung & Sicherung", "p": "Ihre Daten werden lokal auf Ihrem Gerät gespeichert. Wenn Sie die iCloud-Gerätesicherung aktiviert haben, sind Ihre Warranta-Daten in dieser verschlüsselten Apple-Sicherung unter Ihrem eigenen Apple-Konto enthalten. Wir betreiben keine Server, die Ihre Inhalte speichern, und wir können Ihre Daten nicht einsehen."}, {"h": "Ihre Rechte & Kontrolle", "p": "Sie haben stets die Kontrolle. Sie können jedes Objekt jederzeit in der App bearbeiten oder löschen, und durch das Löschen der App werden alle zugehörigen Daten von Ihrem Gerät entfernt. Da wir Ihre personenbezogenen Daten auf keinem Server speichern, gibt es für uns nichts, worauf wir in Ihrem Namen zugreifen, was wir exportieren, berichtigen oder löschen könnten — die Rechte gemäß DSGVO, UK GDPR und CCPA/CPRA werden durch die Konzeption erfüllt."}, {"h": "Dienste von Drittanbietern", "p": "Der einzige beteiligte Drittanbieter ist Apple, das App-Store-Käufe und -Abonnements verarbeitet und die iCloud-Sicherung bereitstellt. Diese Interaktionen unterliegen der eigenen Datenschutzerklärung von Apple unter apple.com/legal/privacy. Warranta integriert keine weiteren Dienste von Drittanbietern, Werbenetzwerke oder Datenhändler."}, {"h": "Datenspeicherung", "p": "Ihre Daten verbleiben auf Ihrem Gerät, solange Sie sie behalten, und werden gelöscht, wenn Sie sie löschen oder die App entfernen. Wir speichern nichts, da wir Ihre Inhalte von vornherein niemals erhalten."}, {"h": "Internationale Nutzer", "p": "Da die gesamte Verarbeitung auf Ihrem Gerät stattfindet, werden Ihre Inhalte nicht an uns übertragen oder über Grenzen hinweg bewegt. Wo auch immer Sie Warranta nutzen, bleiben Ihre Daten bei Ihnen."}, {"h": "Datenschutz für Kinder", "p": "Warranta richtet sich nicht an Kinder unter 13 Jahren und erhebt von niemandem personenbezogene Daten, auch nicht von Kindern."}, {"h": "Änderungen dieser Erklärung", "p": "Wir können diese Erklärung von Zeit zu Zeit aktualisieren. Wesentliche Änderungen werden auf dieser Seite mit einem neuen „Zuletzt aktualisiert“-Datum veröffentlicht; Ihre fortgesetzte Nutzung nach einer Aktualisierung bedeutet, dass Sie die überarbeitete Erklärung akzeptieren."}, {"h": "Kontakt", "p": "Fragen zum Datenschutz? Schreiben Sie an mustafaagulden@gmail.com, und wir helfen Ihnen gerne weiter."}]}, "terms": {"title": "Nutzungsbedingungen", "updated": "Zuletzt aktualisiert: 16. Juli 2026", "intro": "Diese Nutzungsbedingungen („Bedingungen“) regeln Ihre Nutzung der Warranta-App. Durch das Herunterladen oder Verwenden von Warranta erklären Sie sich mit diesen Bedingungen einverstanden. Wenn Sie nicht einverstanden sind, nutzen Sie die App bitte nicht.", "sections": [{"h": "Der Dienst", "p": "Warranta hilft Ihnen, Kaufnachweise zu speichern und Garantie- sowie Rückgabefristen im Blick zu behalten. Es handelt sich ausschließlich um ein Organisationswerkzeug: Es gewährt, verlängert, versichert oder erfüllt keine Garantie, und seine Erinnerungen werden nach bestem Bemühen bereitgestellt und können aus Gründen außerhalb unserer Kontrolle verzögert werden oder ausbleiben. Bestätigen Sie wichtige Termine und Bedingungen stets direkt beim Verkäufer oder Hersteller."}, {"h": "Berechtigung zur Nutzung", "p": "Sie dürfen Warranta nur nutzen, wenn Sie nach dem für Sie geltenden Recht einen bindenden Vertrag schließen können und volljährig sind oder die App unter Aufsicht eines Elternteils oder gesetzlichen Vormunds verwenden."}, {"h": "Lizenz", "p": "Wir gewähren Ihnen eine persönliche, nicht-exklusive, nicht übertragbare, widerrufliche Lizenz zur Nutzung von Warranta für Ihre eigenen persönlichen, nicht-kommerziellen Zwecke, vorbehaltlich dieser Bedingungen und des Lizenzvertrags für Endnutzer lizenzierter Anwendungen von Apple (der Standard-EULA unter apple.com/legal/internet-services/itunes/dev/stdeula)."}, {"h": "Zulässige Nutzung", "p": "Sie verpflichten sich, Warranta rechtmäßig zu nutzen und es weder weiterzuverkaufen, zu vermieten noch weiterzugeben und seinen Quellcode weder zu kopieren, zu ändern, zurückzuentwickeln noch zu extrahieren zu versuchen, außer in dem begrenzten Umfang, in dem geltendes Recht dies trotz dieser Einschränkung ausdrücklich gestattet."}, {"h": "Abonnements & Käufe", "p": "Warranta Pro wird als sich automatisch verlängerndes Abonnement und, sofern verfügbar, als einmaliger Kauf angeboten, jeweils über den App Store abgewickelt. Die Zahlung wird Ihrer Apple-ID belastet. Abonnements verlängern sich automatisch, sofern sie nicht mindestens 24 Stunden vor Ende des laufenden Zeitraums gekündigt werden. Jede kostenlose Testphase geht in ein kostenpflichtiges Abonnement über, sofern sie nicht vor ihrem Ablauf gekündigt wird. Sie können in den Einstellungen Ihres App-Store-Kontos verwalten oder kündigen. Die Preise können je nach Region variieren und werden vor dem Kauf angezeigt."}, {"h": "App-Store-Bedingungen", "p": "Diese Bedingungen bestehen zwischen Ihnen und dem Entwickler von Warranta, nicht Apple, und Apple ist nicht für die App oder deren Inhalte verantwortlich. Apple ist nicht verpflichtet, Wartung oder Support für die App zu leisten. Im größtmöglichen gesetzlich zulässigen Umfang hat Apple keine Gewährleistungspflicht, und alle Ansprüche, Verluste, Haftungen oder Kosten, die der App zuzurechnen sind, liegen in der Verantwortung des Entwicklers, nicht Apples. Apple und seine Tochtergesellschaften sind Drittbegünstigte dieser Bedingungen und können sie Ihnen gegenüber durchsetzen."}, {"h": "Gewährleistungsausschluss", "p": "Warranta wird „wie besehen“ und „wie verfügbar“ bereitgestellt, ohne jegliche ausdrückliche oder stillschweigende Gewährleistung. Wir garantieren nicht, dass Erinnerungen pünktlich zugestellt werden, dass gescannte Daten korrekt sind oder dass die App ununterbrochen oder fehlerfrei funktioniert."}, {"h": "Haftungsbeschränkung", "p": "Im größtmöglichen gesetzlich zulässigen Umfang haften wir nicht für versäumte Garantie- oder Rückgabefristen, Datenverluste oder indirekte, zufällige, besondere oder Folgeschäden, die sich aus Ihrer Nutzung von Warranta ergeben. Nichts in diesen Bedingungen beschränkt oder schließt eine Haftung aus, die nach dem zwingenden Recht Ihres Landes nicht beschränkt oder ausgeschlossen werden kann."}, {"h": "Geistiges Eigentum", "p": "Warranta, sein Name, sein Design und seine Inhalte sind Eigentum des Entwicklers und durch das geltende Recht zum Schutz geistigen Eigentums geschützt. Ihre eigenen Objekte, Fotos und Dokumente bleiben vollständig Ihr Eigentum."}, {"h": "Beendigung", "p": "Diese Lizenz gilt bis zu ihrer Beendigung. Sie endet automatisch, wenn Sie in wesentlicher Weise gegen diese Bedingungen verstoßen, und Sie können sie jederzeit durch Deinstallation der App beenden. Bestimmungen, die ihrer Natur nach eine Beendigung überdauern sollten — wie Gewährleistungsausschlüsse, Haftungsbeschränkungen und Bestimmungen zum geistigen Eigentum — gelten weiter."}, {"h": "Änderungen dieser Bedingungen", "p": "Wir können diese Bedingungen von Zeit zu Zeit aktualisieren. Wesentliche Änderungen werden auf dieser Seite mit einem neuen „Zuletzt aktualisiert“-Datum veröffentlicht. Die fortgesetzte Nutzung von Warranta nach Inkrafttreten der Änderungen bedeutet, dass Sie die aktualisierten Bedingungen akzeptieren."}, {"h": "Anwendbares Recht", "p": "Diese Bedingungen unterliegen dem Recht der Republik Türkei, unbeschadet etwaiger zwingender verbraucherschutzrechtlicher Rechte, die Ihnen nach dem Recht Ihres Wohnsitzlandes zustehen und weiterhin gelten."}, {"h": "Kontakt", "p": "Fragen zu diesen Bedingungen? Schreiben Sie an mustafaagulden@gmail.com."}]}}, "fr": {"lang": "fr", "name": "Français", "privacy": {"title": "Politique de confidentialité", "updated": "Dernière mise à jour : 16 juillet 2026", "intro": "Warranta est un coffre-fort respectueux de la vie privée pour vos reçus, vos garanties et vos délais de retour. Il est conçu pour que tout ce que vous ajoutez reste sur votre appareil. Cette politique explique, en langage clair, quelles données sont concernées et comment elles sont traitées.", "sections": [{"h": "Données que nous collectons", "p": "Aucune. Warranta ne nécessite aucun compte et ne collecte, ne transmet, ne vend ni ne partage vos données personnelles. Vos articles, photos, documents, prix et notes ne quittent jamais votre appareil, sauf dans le cadre de votre propre sauvegarde d’appareil (voir « Stockage et sauvegarde »)."}, {"h": "Traitement sur l’appareil", "p": "Lorsque vous numérisez un reçu ou une garantie, le texte est lu et les champs sont remplis à l’aide du framework Vision d’Apple exécuté sur l’appareil et de l’intelligence embarquée. L’image et son texte sont traités entièrement sur votre iPhone et ne sont jamais envoyés à nous ni à un tiers."}, {"h": "Utilisation du réseau", "p": "La seule activité réseau concerne l’App Store d’Apple, pour les achats et les abonnements. Si vous achetez Warranta Pro, un enregistrement facultatif peut envoyer un unique identifiant de transaction Apple anonyme afin que votre abonnement puisse être reconnu — il ne contient aucun nom, aucune adresse e-mail ni aucun contenu d’article. Warranta ne comporte aucun SDK d’analyse, de publicité ou de suivi, de quelque nature que ce soit, et n’affiche aucune publicité."}, {"h": "Autorisations", "p": "Warranta peut demander l’accès à l’Appareil photo (pour photographier un reçu ou une garantie), à la Photothèque (pour choisir une image existante) et aux Notifications (pour vous rappeler avant l’expiration d’une garantie ou d’un délai de retour). Chaque autorisation est facultative, demandée uniquement lorsque c’est nécessaire, et utilisée uniquement à la fin indiquée."}, {"h": "Stockage et sauvegarde", "p": "Vos données sont stockées localement sur votre appareil. Si vous avez activé la sauvegarde d’appareil iCloud, vos données Warranta sont incluses dans cette sauvegarde Apple chiffrée, sous votre propre compte Apple. Nous n’exploitons aucun serveur contenant vos contenus et nous ne pouvons pas voir vos données."}, {"h": "Vos droits et votre contrôle", "p": "Vous gardez toujours le contrôle. Vous pouvez modifier ou supprimer n’importe quel article dans l’application à tout moment, et supprimer l’application efface toutes ses données de votre appareil. Comme nous ne détenons vos données personnelles sur aucun serveur, il n’y a rien que nous puissions consulter, exporter, corriger ou effacer en votre nom — les droits prévus par le RGPD, le RGPD britannique et le CCPA/CPRA sont satisfaits dès la conception."}, {"h": "Services tiers", "p": "Le seul tiers impliqué est Apple, qui traite les achats et abonnements de l’App Store et fournit la sauvegarde iCloud. Ces interactions sont régies par la propre politique de confidentialité d’Apple, disponible sur apple.com/legal/privacy. Warranta n’intègre aucun autre service tiers, réseau publicitaire ni courtier en données."}, {"h": "Conservation des données", "p": "Vos données restent sur votre appareil aussi longtemps que vous les conservez et sont supprimées lorsque vous les supprimez ou désinstallez l’application. Nous ne conservons rien, car nous ne recevons jamais vos contenus en premier lieu."}, {"h": "Utilisateurs internationaux", "p": "Comme tout le traitement a lieu sur votre appareil, vos contenus ne nous sont pas transférés ni déplacés au-delà des frontières. Où que vous utilisiez Warranta, vos données restent avec vous."}, {"h": "Confidentialité des enfants", "p": "Warranta ne s’adresse pas aux enfants de moins de 13 ans et ne collecte aucune donnée personnelle de quiconque, y compris des enfants."}, {"h": "Modifications de cette politique", "p": "Nous pouvons mettre à jour cette politique de temps à autre. Les modifications importantes seront publiées sur cette page avec une nouvelle date de « dernière mise à jour » ; votre utilisation continue après une mise à jour signifie que vous acceptez la politique révisée."}, {"h": "Contact", "p": "Des questions sur la confidentialité ? Écrivez à mustafaagulden@gmail.com et nous serons ravis de vous aider."}]}, "terms": {"title": "Conditions d’utilisation", "updated": "Dernière mise à jour : 16 juillet 2026", "intro": "Les présentes conditions d’utilisation (« Conditions ») régissent votre utilisation de l’application Warranta. En téléchargeant ou en utilisant Warranta, vous acceptez ces Conditions. Si vous n’êtes pas d’accord, veuillez ne pas utiliser l’application.", "sections": [{"h": "Le service", "p": "Warranta vous aide à conserver vos preuves d’achat et à suivre vos délais de garantie et de retour. Il s’agit uniquement d’un outil d’organisation : il ne fournit, ne prolonge, ne garantit ni n’honore aucune garantie, et ses rappels sont fournis dans la mesure du possible et peuvent être retardés ou manqués pour des raisons indépendantes de notre volonté. Confirmez toujours les dates et conditions importantes directement auprès du vendeur ou du fabricant."}, {"h": "Éligibilité", "p": "Vous ne pouvez utiliser Warranta que si vous êtes en mesure de conclure un contrat contraignant en vertu du droit qui vous est applicable, et que vous avez atteint l’âge de la majorité dans votre pays ou utilisez l’application sous la supervision d’un parent ou d’un tuteur légal."}, {"h": "Licence", "p": "Nous vous accordons une licence personnelle, non exclusive, non transférable et révocable pour utiliser Warranta à vos propres fins personnelles et non commerciales, sous réserve des présentes Conditions et du Contrat de licence utilisateur final des applications sous licence d’Apple (le CLUF standard disponible sur apple.com/legal/internet-services/itunes/dev/stdeula)."}, {"h": "Utilisation acceptable", "p": "Vous acceptez d’utiliser Warranta de manière licite et de ne pas le revendre, le louer ni le redistribuer, ni de copier, modifier, désosser ou tenter d’extraire son code source, sauf dans la mesure limitée où la loi applicable l’autorise expressément malgré cette restriction."}, {"h": "Abonnements et achats", "p": "Warranta Pro est proposé sous forme d’abonnements à renouvellement automatique et, lorsque disponible, d’un achat unique, tous traités par l’App Store. Le paiement est prélevé sur votre identifiant Apple. Les abonnements se renouvellent automatiquement, sauf s’ils sont annulés au moins 24 heures avant la fin de la période en cours. Toute période d’essai gratuite se convertit en abonnement payant si elle n’est pas annulée avant son expiration. Vous pouvez gérer ou annuler dans les réglages de votre compte App Store. Les prix peuvent varier selon la région et sont affichés avant l’achat."}, {"h": "Conditions de l’App Store", "p": "Les présentes Conditions sont conclues entre vous et le développeur de Warranta, et non Apple, et Apple n’est pas responsable de l’application ni de son contenu. Apple n’a aucune obligation de fournir un quelconque entretien ou support pour l’application. Dans toute la mesure permise par la loi, Apple n’a aucune obligation de garantie, et toute réclamation, perte, responsabilité ou coût imputable à l’application relève de la responsabilité du développeur, et non d’Apple. Apple et ses filiales sont des tiers bénéficiaires des présentes Conditions et peuvent les faire valoir à votre encontre."}, {"h": "Exclusion de garanties", "p": "Warranta est fourni « en l’état » et « selon disponibilité », sans garantie d’aucune sorte, expresse ou implicite. Nous ne garantissons pas que les rappels seront délivrés à temps, que les données numérisées seront exactes, ni que l’application sera ininterrompue ou exempte d’erreurs."}, {"h": "Limitation de responsabilité", "p": "Dans toute la mesure permise par la loi, nous ne sommes pas responsables des délais de garantie ou de retour manqués, des pertes de données, ni des dommages indirects, accessoires, spéciaux ou consécutifs découlant de votre utilisation de Warranta. Rien dans les présentes Conditions ne limite ni n’exclut une responsabilité qui ne peut être limitée ou exclue en vertu du droit impératif de votre pays."}, {"h": "Propriété intellectuelle", "p": "Warranta, son nom, sa conception et son contenu sont la propriété du développeur et protégés par le droit applicable de la propriété intellectuelle. Vos propres articles, photos et documents restent entièrement les vôtres."}, {"h": "Résiliation", "p": "La présente licence reste en vigueur jusqu’à sa résiliation. Elle prend fin automatiquement si vous enfreignez ces Conditions de manière substantielle, et vous pouvez y mettre fin à tout moment en désinstallant l’application. Les dispositions qui, par leur nature, devraient survivre à la résiliation — telles que les exclusions de garantie, la limitation de responsabilité et les dispositions relatives à la propriété intellectuelle — continueront de s’appliquer."}, {"h": "Modifications de ces conditions", "p": "Nous pouvons mettre à jour ces Conditions de temps à autre. Les modifications importantes seront publiées sur cette page avec une nouvelle date de « dernière mise à jour ». L’utilisation continue de Warranta après l’entrée en vigueur des modifications signifie que vous acceptez les Conditions mises à jour."}, {"h": "Droit applicable", "p": "Les présentes Conditions sont régies par le droit de la République de Türkiye, sans préjudice des droits impératifs de protection des consommateurs dont vous bénéficiez en vertu du droit de votre pays de résidence, qui continuent de s’appliquer."}, {"h": "Contact", "p": "Des questions sur ces Conditions ? Écrivez à mustafaagulden@gmail.com."}]}}, "es": {"lang": "es", "name": "Español", "privacy": {"title": "Política de privacidad", "updated": "Última actualización: 16 de julio de 2026", "intro": "Warranta es una bóveda centrada en la privacidad para tus recibos, garantías y plazos de devolución. Está diseñada para que todo lo que añadas permanezca en tu dispositivo. Esta política explica, en lenguaje claro, qué datos están implicados y cómo se tratan.", "sections": [{"h": "Datos que recopilamos", "p": "Ninguno. Warranta no requiere ninguna cuenta y no recopila, transmite, vende ni comparte tus datos personales. Tus artículos, fotos, documentos, precios y notas nunca salen de tu dispositivo, salvo dentro de tu propia copia de seguridad del dispositivo (véase «Almacenamiento y copia de seguridad»)."}, {"h": "Procesamiento en el dispositivo", "p": "Cuando escaneas un recibo o una garantía, el texto se lee y los campos se rellenan utilizando el framework Vision de Apple en el dispositivo y la inteligencia integrada. La imagen y su texto se procesan íntegramente en tu iPhone y nunca se suben a nosotros ni a ningún tercero."}, {"h": "Uso de la red", "p": "La única actividad de red se realiza con el App Store de Apple, para las compras y suscripciones. Si compras Warranta Pro, un registro opcional puede enviar un único identificador de transacción de Apple anónimo para que tu suscripción pueda reconocerse; no contiene ningún nombre, correo electrónico ni contenido de artículos. Warranta no incluye ningún SDK de análisis, publicidad o seguimiento de ningún tipo, y no muestra anuncios."}, {"h": "Permisos", "p": "Warranta puede solicitar acceso a la Cámara (para fotografiar un recibo o una garantía), a la Fototeca (para elegir una imagen existente) y a las Notificaciones (para recordarte antes de que expire una garantía o un plazo de devolución). Cada permiso es opcional, se solicita solo cuando es necesario y se utiliza únicamente para el fin indicado."}, {"h": "Almacenamiento y copia de seguridad", "p": "Tus datos se almacenan localmente en tu dispositivo. Si tienes activada la copia de seguridad del dispositivo en iCloud, tus datos de Warranta se incluyen en esa copia de seguridad cifrada de Apple, bajo tu propia cuenta de Apple. No operamos ningún servidor que albergue tu contenido y no podemos ver tus datos."}, {"h": "Tus derechos y control", "p": "Siempre tienes el control. Puedes editar o eliminar cualquier artículo dentro de la aplicación en cualquier momento, y eliminar la aplicación borra todos sus datos de tu dispositivo. Dado que no conservamos tus datos personales en ningún servidor, no hay nada a lo que podamos acceder, exportar, corregir o borrar en tu nombre; los derechos previstos por el RGPD, el RGPD del Reino Unido y la CCPA/CPRA se satisfacen desde el diseño."}, {"h": "Servicios de terceros", "p": "El único tercero implicado es Apple, que procesa las compras y suscripciones del App Store y proporciona la copia de seguridad de iCloud. Esas interacciones se rigen por la propia política de privacidad de Apple, disponible en apple.com/legal/privacy. Warranta no integra ningún otro servicio de terceros, red publicitaria ni intermediario de datos."}, {"h": "Conservación de datos", "p": "Tus datos permanecen en tu dispositivo mientras los conserves y se eliminan cuando los borras o retiras la aplicación. No conservamos nada, porque nunca recibimos tu contenido en primer lugar."}, {"h": "Usuarios internacionales", "p": "Dado que todo el procesamiento ocurre en tu dispositivo, tu contenido no se nos transfiere ni se traslada a través de fronteras. Dondequiera que utilices Warranta, tus datos permanecen contigo."}, {"h": "Privacidad de los menores", "p": "Warranta no está dirigida a menores de 13 años y no recopila datos personales de nadie, incluidos los menores."}, {"h": "Cambios en esta política", "p": "Podemos actualizar esta política de vez en cuando. Los cambios importantes se publicarán en esta página con una nueva fecha de «última actualización»; tu uso continuado tras una actualización significa que aceptas la política revisada."}, {"h": "Contacto", "p": "¿Preguntas sobre privacidad? Escribe a mustafaagulden@gmail.com y estaremos encantados de ayudarte."}]}, "terms": {"title": "Condiciones del servicio", "updated": "Última actualización: 16 de julio de 2026", "intro": "Estas Condiciones del servicio («Condiciones») rigen tu uso de la aplicación Warranta. Al descargar o utilizar Warranta, aceptas estas Condiciones. Si no estás de acuerdo, por favor no utilices la aplicación.", "sections": [{"h": "El servicio", "p": "Warranta te ayuda a guardar comprobantes de compra y a llevar el control de los plazos de garantía y devolución. Es únicamente una herramienta de organización: no proporciona, amplía, respalda ni cumple ninguna garantía, y sus recordatorios se ofrecen según el mejor esfuerzo y pueden retrasarse o perderse por razones ajenas a nuestro control. Confirma siempre las fechas y condiciones importantes directamente con el vendedor o el fabricante."}, {"h": "Elegibilidad", "p": "Solo puedes utilizar Warranta si puedes celebrar un contrato vinculante conforme a la ley que te sea aplicable, y si eres mayor de edad en tu país o utilizas la aplicación bajo la supervisión de un progenitor o tutor legal."}, {"h": "Licencia", "p": "Te concedemos una licencia personal, no exclusiva, intransferible y revocable para utilizar Warranta con tus propios fines personales y no comerciales, con sujeción a estas Condiciones y al Contrato de licencia de usuario final de aplicaciones con licencia de Apple (el CLUF estándar disponible en apple.com/legal/internet-services/itunes/dev/stdeula)."}, {"h": "Uso aceptable", "p": "Aceptas utilizar Warranta de forma lícita y no revenderla, alquilarla ni redistribuirla, ni copiar, modificar, aplicar ingeniería inversa o intentar extraer su código fuente, salvo en la medida limitada en que la ley aplicable lo permita expresamente pese a esta restricción."}, {"h": "Suscripciones y compras", "p": "Warranta Pro se ofrece como suscripciones de renovación automática y, cuando esté disponible, como una compra única, todas procesadas por el App Store. El pago se carga a tu Apple ID. Las suscripciones se renuevan automáticamente a menos que se cancelen al menos 24 horas antes del final del período en curso. Cualquier prueba gratuita se convierte en una suscripción de pago a menos que se cancele antes de que finalice. Puedes gestionar o cancelar en los ajustes de tu cuenta del App Store. Los precios pueden variar según la región y se muestran antes de la compra."}, {"h": "Condiciones del App Store", "p": "Estas Condiciones se celebran entre tú y el desarrollador de Warranta, no Apple, y Apple no es responsable de la aplicación ni de su contenido. Apple no tiene ninguna obligación de prestar mantenimiento o soporte para la aplicación. En la máxima medida permitida por la ley, Apple no tiene ninguna obligación de garantía, y cualquier reclamación, pérdida, responsabilidad o coste atribuible a la aplicación es responsabilidad del desarrollador, no de Apple. Apple y sus filiales son terceros beneficiarios de estas Condiciones y pueden hacerlas valer frente a ti."}, {"h": "Renuncia de garantías", "p": "Warranta se proporciona «tal cual» y «según disponibilidad», sin garantías de ningún tipo, ya sean expresas o implícitas. No garantizamos que los recordatorios se entreguen a tiempo, que los datos escaneados sean exactos, ni que la aplicación funcione de forma ininterrumpida o sin errores."}, {"h": "Limitación de responsabilidad", "p": "En la máxima medida permitida por la ley, no somos responsables de ningún plazo de garantía o devolución incumplido, de pérdidas de datos, ni de daños indirectos, incidentales, especiales o consecuentes derivados de tu uso de Warranta. Nada en estas Condiciones limita ni excluye responsabilidades que no puedan limitarse o excluirse conforme al derecho imperativo de tu país."}, {"h": "Propiedad intelectual", "p": "Warranta, su nombre, su diseño y su contenido son propiedad del desarrollador y están protegidos por la legislación aplicable de propiedad intelectual. Tus propios artículos, fotos y documentos siguen siendo enteramente tuyos."}, {"h": "Terminación", "p": "Esta licencia continúa hasta su terminación. Finaliza automáticamente si incumples estas Condiciones de manera sustancial, y puedes terminarla en cualquier momento desinstalando la aplicación. Las disposiciones que por su naturaleza deban subsistir tras la terminación —como las renuncias de garantía, la limitación de responsabilidad y las condiciones de propiedad intelectual— seguirán aplicándose."}, {"h": "Cambios en estas condiciones", "p": "Podemos actualizar estas Condiciones de vez en cuando. Los cambios importantes se publicarán en esta página con una nueva fecha de «última actualización». El uso continuado de Warranta después de que los cambios entren en vigor significa que aceptas las Condiciones actualizadas."}, {"h": "Ley aplicable", "p": "Estas Condiciones se rigen por las leyes de la República de Türkiye, sin perjuicio de los derechos imperativos de protección al consumidor que te correspondan conforme a la ley de tu país de residencia, que siguen siendo aplicables."}, {"h": "Contacto", "p": "¿Preguntas sobre estas Condiciones? Escribe a mustafaagulden@gmail.com."}]}}, "it": {"lang": "it", "name": "Italiano", "privacy": {"title": "Informativa sulla privacy", "updated": "Ultimo aggiornamento: 16 luglio 2026", "intro": "Warranta è un archivio orientato alla privacy per le tue ricevute, garanzie e finestre di reso. È progettato affinché tutto ciò che aggiungi rimanga sul tuo dispositivo. Questa informativa spiega, in un linguaggio semplice, quali dati sono coinvolti e come vengono trattati.", "sections": [{"h": "Dati che raccogliamo", "p": "Nessuno. Warranta non richiede alcun account e non raccoglie, trasmette, vende o condivide i tuoi dati personali. I tuoi articoli, foto, documenti, prezzi e note non lasciano mai il tuo dispositivo, se non all'interno del backup del tuo stesso dispositivo (vedi «Archiviazione e backup»)."}, {"h": "Elaborazione sul dispositivo", "p": "Quando scansioni una ricevuta o una garanzia, il testo viene letto e i campi vengono compilati utilizzando il framework Vision di Apple e l'intelligenza integrata, entrambi eseguiti sul dispositivo. L'immagine e il relativo testo sono elaborati interamente sul tuo iPhone e non vengono mai caricati verso di noi o verso terze parti."}, {"h": "Uso della rete", "p": "L'unica attività di rete avviene con l'App Store di Apple, per acquisti e abbonamenti. Se acquisti Warranta Pro, una registrazione facoltativa può inviare un singolo identificativo anonimo della transazione Apple affinché il tuo abbonamento possa essere riconosciuto — non contiene alcun nome, email o contenuto degli articoli. Warranta non include alcun SDK di analisi, pubblicità o tracciamento di alcun tipo e non mostra annunci."}, {"h": "Autorizzazioni", "p": "Warranta può richiedere l'accesso alla Fotocamera (per fotografare una ricevuta o una garanzia), alla Libreria foto (per scegliere un'immagine esistente) e alle Notifiche (per ricordarti la scadenza di una garanzia o di una finestra di reso). Ogni autorizzazione è facoltativa, richiesta solo quando necessaria e utilizzata esclusivamente per lo scopo indicato."}, {"h": "Archiviazione e backup", "p": "I tuoi dati sono conservati localmente sul tuo dispositivo. Se hai abilitato il backup del dispositivo su iCloud, i dati di Warranta sono inclusi in quel backup crittografato di Apple, sotto il tuo account Apple. Non gestiamo alcun server che contenga i tuoi contenuti e non possiamo vedere i tuoi dati."}, {"h": "I tuoi diritti e il tuo controllo", "p": "Hai sempre il controllo. Puoi modificare o eliminare qualsiasi articolo all'interno dell'app in qualsiasi momento, e l'eliminazione dell'app rimuove tutti i relativi dati dal tuo dispositivo. Poiché non conserviamo i tuoi dati personali su alcun server, non c'è nulla a cui possiamo accedere, che possiamo esportare, correggere o cancellare per tuo conto — i diritti previsti dal GDPR, dal GDPR del Regno Unito e dal CCPA/CPRA sono soddisfatti per impostazione predefinita."}, {"h": "Servizi di terze parti", "p": "L'unica terza parte coinvolta è Apple, che elabora gli acquisti e gli abbonamenti dell'App Store e fornisce il backup iCloud. Tali interazioni sono disciplinate dall'Informativa sulla privacy di Apple all'indirizzo apple.com/legal/privacy. Warranta non integra altri servizi di terze parti, reti pubblicitarie o intermediari di dati."}, {"h": "Conservazione dei dati", "p": "I tuoi dati rimangono sul tuo dispositivo per tutto il tempo in cui li conservi e vengono eliminati quando li elimini o rimuovi l'app. Noi non conserviamo nulla, perché non riceviamo mai i tuoi contenuti fin dall'inizio."}, {"h": "Utenti internazionali", "p": "Poiché tutta l'elaborazione avviene sul tuo dispositivo, i tuoi contenuti non vengono trasferiti a noi né spostati oltre i confini nazionali. Ovunque tu utilizzi Warranta, i tuoi dati restano con te."}, {"h": "Privacy dei minori", "p": "Warranta non è rivolta ai minori di 13 anni e non raccoglie dati personali da nessuno, compresi i minori."}, {"h": "Modifiche a questa informativa", "p": "Potremmo aggiornare questa informativa di tanto in tanto. Le modifiche sostanziali saranno pubblicate su questa pagina con una nuova data di «ultimo aggiornamento»; il tuo utilizzo continuato dopo un aggiornamento significa che accetti l'informativa rivista."}, {"h": "Contatti", "p": "Domande sulla privacy? Scrivi a mustafaagulden@gmail.com e saremo lieti di aiutarti."}]}, "terms": {"title": "Termini di servizio", "updated": "Ultimo aggiornamento: 16 luglio 2026", "intro": "I presenti Termini di servizio («Termini») disciplinano l'uso dell'app Warranta. Scaricando o utilizzando Warranta, accetti questi Termini. Se non li accetti, ti preghiamo di non utilizzare l'app.", "sections": [{"h": "Il servizio", "p": "Warranta ti aiuta a conservare le prove d'acquisto e a tenere traccia delle garanzie e delle finestre di reso. È esclusivamente uno strumento organizzativo: non fornisce, estende, garantisce né onora alcuna garanzia, e i suoi promemoria sono forniti secondo il principio del massimo impegno e possono essere ritardati o mancati per motivi al di fuori del nostro controllo. Verifica sempre le date e le condizioni importanti direttamente con il venditore o il produttore."}, {"h": "Requisiti di idoneità", "p": "Puoi utilizzare Warranta solo se sei in grado di stipulare un contratto vincolante ai sensi della legge a te applicabile e se hai raggiunto la maggiore età nel tuo paese, oppure se utilizzi l'app sotto la supervisione di un genitore o tutore legale."}, {"h": "Licenza", "p": "Ti concediamo una licenza personale, non esclusiva, non trasferibile e revocabile per utilizzare Warranta per i tuoi scopi personali e non commerciali, nel rispetto dei presenti Termini e del Contratto di licenza con l'utente finale dell'applicazione concessa in licenza di Apple (il EULA standard all'indirizzo apple.com/legal/internet-services/itunes/dev/stdeula)."}, {"h": "Uso accettabile", "p": "Accetti di utilizzare Warranta in modo lecito e di non rivenderla, noleggiarla o ridistribuirla, né di copiarla, modificarla, sottoporla a reverse engineering o tentare di estrarne il codice sorgente, salvo nella limitata misura in cui la legge applicabile lo consenta espressamente nonostante tale restrizione."}, {"h": "Abbonamenti e acquisti", "p": "Warranta Pro è offerto sotto forma di abbonamenti a rinnovo automatico e, ove disponibile, come acquisto una tantum, il tutto elaborato dall'App Store. Il pagamento viene addebitato al tuo ID Apple. Gli abbonamenti si rinnovano automaticamente salvo cancellazione almeno 24 ore prima della fine del periodo in corso. Qualsiasi prova gratuita si converte in abbonamento a pagamento salvo cancellazione prima della sua scadenza. Puoi gestire o annullare l'abbonamento nelle impostazioni del tuo account App Store. I prezzi possono variare in base alla regione e vengono mostrati prima dell'acquisto."}, {"h": "Termini dell'App Store", "p": "I presenti Termini sono stipulati tra te e lo sviluppatore di Warranta, non Apple, e Apple non è responsabile dell'app né dei suoi contenuti. Apple non ha alcun obbligo di fornire manutenzione o assistenza per l'app. Nella misura massima consentita dalla legge, Apple non ha alcun obbligo di garanzia, e qualsiasi rivendicazione, perdita, responsabilità o costo attribuibile all'app è responsabilità dello sviluppatore, non di Apple. Apple e le sue società controllate sono terzi beneficiari dei presenti Termini e possono farli valere nei tuoi confronti."}, {"h": "Esclusione di garanzie", "p": "Warranta è fornita «così com'è» e «come disponibile», senza garanzie di alcun tipo, espresse o implicite. Non garantiamo che i promemoria vengano consegnati puntualmente, che i dati scansionati siano accurati, o che l'app sia priva di interruzioni o di errori."}, {"h": "Limitazione di responsabilità", "p": "Nella misura massima consentita dalla legge, non siamo responsabili per eventuali scadenze di garanzia o di reso mancate, per la perdita di dati, o per danni indiretti, incidentali, speciali o consequenziali derivanti dall'uso di Warranta. Nulla nei presenti Termini limita o esclude la responsabilità che non può essere limitata o esclusa ai sensi delle norme imperative del tuo paese."}, {"h": "Proprietà intellettuale", "p": "Warranta, il suo nome, il design e i contenuti sono di proprietà dello sviluppatore e protetti dalla legge applicabile in materia di proprietà intellettuale. I tuoi articoli, foto e documenti restano interamente tuoi."}, {"h": "Risoluzione", "p": "La presente licenza rimane in vigore fino alla sua risoluzione. Termina automaticamente se violi i presenti Termini in modo sostanziale, e puoi porvi fine in qualsiasi momento disinstallando l'app. Le disposizioni che per loro natura devono sopravvivere alla risoluzione — quali le esclusioni di garanzia, la limitazione di responsabilità e i termini sulla proprietà intellettuale — continueranno ad applicarsi."}, {"h": "Modifiche ai presenti termini", "p": "Potremmo aggiornare i presenti Termini di tanto in tanto. Le modifiche sostanziali saranno pubblicate su questa pagina con una nuova data di «ultimo aggiornamento». L'uso continuato di Warranta dopo l'entrata in vigore delle modifiche significa che accetti i Termini aggiornati."}, {"h": "Legge applicabile", "p": "I presenti Termini sono disciplinati dalle leggi della Repubblica di Türkiye, fatti salvi eventuali diritti imperativi di tutela dei consumatori a te spettanti ai sensi della legge del tuo paese di residenza, che continuano ad applicarsi."}, {"h": "Contatti", "p": "Domande sui presenti Termini? Scrivi a mustafaagulden@gmail.com."}]}}, "pt": {"lang": "pt", "name": "Português", "privacy": {"title": "Política de Privacidade", "updated": "Última atualização: 16 de julho de 2026", "intro": "O Warranta é um cofre focado na privacidade para os seus recibos, garantias e prazos de devolução. Foi concebido para que tudo o que adicionar permaneça no seu dispositivo. Esta política explica, em linguagem simples, quais os dados envolvidos e como são tratados.", "sections": [{"h": "Dados que recolhemos", "p": "Nenhum. O Warranta não exige qualquer conta e não recolhe, transmite, vende nem partilha os seus dados pessoais. Os seus itens, fotos, documentos, preços e notas nunca saem do seu dispositivo, exceto dentro do backup do seu próprio dispositivo (consulte «Armazenamento e backup»)."}, {"h": "Processamento no dispositivo", "p": "Quando digitaliza um recibo ou uma garantia, o texto é lido e os campos são preenchidos utilizando a estrutura Vision da Apple e a inteligência integrada no dispositivo. A imagem e o respetivo texto são processados inteiramente no seu iPhone e nunca são carregados para nós nem para terceiros."}, {"h": "Utilização da rede", "p": "A única atividade de rede ocorre com a App Store da Apple, para compras e subscrições. Se adquirir o Warranta Pro, um registo opcional pode enviar um único identificador anónimo de transação da Apple, para que a sua subscrição possa ser reconhecida — não contém qualquer nome, e-mail ou conteúdo de itens. O Warranta não inclui quaisquer SDK de análise, publicidade ou rastreamento de qualquer tipo e não apresenta anúncios."}, {"h": "Permissões", "p": "O Warranta pode solicitar acesso à Câmara (para fotografar um recibo ou uma garantia), à Galeria de fotos (para escolher uma imagem existente) e às Notificações (para o lembrar antes de uma garantia ou prazo de devolução expirar). Cada permissão é opcional, solicitada apenas quando necessária e utilizada exclusivamente para o fim indicado."}, {"h": "Armazenamento e backup", "p": "Os seus dados são armazenados localmente no seu dispositivo. Se tiver o backup do dispositivo no iCloud ativado, os seus dados do Warranta são incluídos nesse backup encriptado da Apple, sob a sua própria conta Apple. Não operamos quaisquer servidores que contenham o seu conteúdo e não conseguimos ver os seus dados."}, {"h": "Os seus direitos e controlo", "p": "Está sempre no controlo. Pode editar ou eliminar qualquer item dentro da aplicação a qualquer momento, e eliminar a aplicação remove todos os respetivos dados do seu dispositivo. Uma vez que não guardamos os seus dados pessoais em qualquer servidor, não há nada a que possamos aceder, exportar, corrigir ou apagar em seu nome — os direitos previstos no RGPD, no RGPD do Reino Unido e no CCPA/CPRA são satisfeitos por conceção."}, {"h": "Serviços de terceiros", "p": "O único terceiro envolvido é a Apple, que processa as compras e subscrições da App Store e fornece o backup do iCloud. Essas interações são regidas pela própria Política de Privacidade da Apple em apple.com/legal/privacy. O Warranta não integra quaisquer outros serviços de terceiros, redes de publicidade ou corretores de dados."}, {"h": "Retenção de dados", "p": "Os seus dados permanecem no seu dispositivo enquanto os mantiver e são eliminados quando os eliminar ou remover a aplicação. Não retemos nada, porque nunca recebemos o seu conteúdo em primeiro lugar."}, {"h": "Utilizadores internacionais", "p": "Uma vez que todo o processamento acontece no seu dispositivo, o seu conteúdo não é transferido para nós nem movido através de fronteiras. Onde quer que utilize o Warranta, os seus dados permanecem consigo."}, {"h": "Privacidade das crianças", "p": "O Warranta não se destina a crianças com menos de 13 anos e não recolhe dados pessoais de ninguém, incluindo crianças."}, {"h": "Alterações a esta política", "p": "Poderemos atualizar esta política periodicamente. As alterações substanciais serão publicadas nesta página com uma nova data de «última atualização»; a sua utilização continuada após uma atualização significa que aceita a política revista."}, {"h": "Contacto", "p": "Dúvidas sobre privacidade? Envie um e-mail para mustafaagulden@gmail.com e teremos todo o gosto em ajudar."}]}, "terms": {"title": "Termos de Serviço", "updated": "Última atualização: 16 de julho de 2026", "intro": "Estes Termos de Serviço («Termos») regem a utilização da aplicação Warranta. Ao descarregar ou utilizar o Warranta, concorda com estes Termos. Se não concordar, por favor não utilize a aplicação.", "sections": [{"h": "O serviço", "p": "O Warranta ajuda-o a guardar provas de compra e a acompanhar garantias e prazos de devolução. É apenas uma ferramenta de organização: não fornece, prolonga, subscreve nem honra qualquer garantia, e os seus lembretes são fornecidos numa base de melhor esforço, podendo ser atrasados ou falhados por motivos fora do nosso controlo. Confirme sempre datas e condições importantes diretamente com o vendedor ou o fabricante."}, {"h": "Elegibilidade", "p": "Só pode utilizar o Warranta se puder celebrar um contrato vinculativo ao abrigo da lei que lhe é aplicável e se tiver atingido a maioridade no seu país, ou se utilizar a aplicação sob a supervisão de um progenitor ou tutor legal."}, {"h": "Licença", "p": "Concedemos-lhe uma licença pessoal, não exclusiva, intransmissível e revogável para utilizar o Warranta para os seus próprios fins pessoais e não comerciais, sujeita a estes Termos e ao Contrato de Licença de Utilizador Final da Aplicação Licenciada da Apple (o EULA padrão em apple.com/legal/internet-services/itunes/dev/stdeula)."}, {"h": "Utilização aceitável", "p": "Concorda em utilizar o Warranta de forma lícita e em não o revender, alugar ou redistribuir, nem copiar, modificar, fazer engenharia inversa ou tentar extrair o seu código-fonte, exceto na medida limitada em que a lei aplicável o permita expressamente, apesar desta restrição."}, {"h": "Subscrições e compras", "p": "O Warranta Pro é oferecido como subscrições de renovação automática e, quando disponível, como uma compra única, tudo processado pela App Store. O pagamento é cobrado ao seu ID Apple. As subscrições renovam-se automaticamente, exceto se forem canceladas com pelo menos 24 horas de antecedência em relação ao fim do período atual. Qualquer período de avaliação gratuito converte-se numa subscrição paga, exceto se for cancelado antes de terminar. Pode gerir ou cancelar nas definições da sua conta da App Store. Os preços podem variar consoante a região e são apresentados antes da compra."}, {"h": "Termos da App Store", "p": "Estes Termos são celebrados entre si e o programador do Warranta, e não a Apple, e a Apple não é responsável pela aplicação nem pelo seu conteúdo. A Apple não tem qualquer obrigação de fornecer manutenção ou suporte à aplicação. Na medida máxima permitida por lei, a Apple não tem qualquer obrigação de garantia, e quaisquer reclamações, perdas, responsabilidades ou custos atribuíveis à aplicação são da responsabilidade do programador, e não da Apple. A Apple e as suas subsidiárias são terceiros beneficiários destes Termos e podem exercê-los contra si."}, {"h": "Exclusão de garantias", "p": "O Warranta é fornecido «tal como está» e «conforme disponível», sem garantias de qualquer tipo, expressas ou implícitas. Não garantimos que os lembretes sejam entregues a tempo, que os dados digitalizados sejam precisos, ou que a aplicação seja ininterrupta ou livre de erros."}, {"h": "Limitação de responsabilidade", "p": "Na medida máxima permitida por lei, não somos responsáveis por qualquer prazo de garantia ou de devolução falhado, por dados perdidos, ou por danos indiretos, incidentais, especiais ou consequenciais decorrentes da sua utilização do Warranta. Nada nestes Termos limita ou exclui a responsabilidade que não possa ser limitada ou excluída ao abrigo da lei imperativa do seu país."}, {"h": "Propriedade intelectual", "p": "O Warranta, o seu nome, design e conteúdo são propriedade do programador e estão protegidos pela lei aplicável em matéria de propriedade intelectual. Os seus próprios itens, fotos e documentos permanecem inteiramente seus."}, {"h": "Rescisão", "p": "Esta licença mantém-se em vigor até ser rescindida. Termina automaticamente se violar estes Termos de forma substancial, e pode terminá-la a qualquer momento desinstalando a aplicação. As disposições que, pela sua natureza, devam subsistir após a rescisão — tais como as exclusões de garantia, a limitação de responsabilidade e os termos de propriedade intelectual — continuarão a aplicar-se."}, {"h": "Alterações a estes termos", "p": "Poderemos atualizar estes Termos periodicamente. As alterações substanciais serão publicadas nesta página com uma nova data de «última atualização». A utilização continuada do Warranta após as alterações entrarem em vigor significa que aceita os Termos atualizados."}, {"h": "Lei aplicável", "p": "Estes Termos são regidos pelas leis da República da Türkiye, sem prejuízo de quaisquer direitos imperativos de proteção do consumidor a que tenha direito ao abrigo da lei do seu país de residência, os quais continuam a aplicar-se."}, {"h": "Contacto", "p": "Dúvidas sobre estes Termos? Envie um e-mail para mustafaagulden@gmail.com."}]}}, "nl": {"lang": "nl", "name": "Nederlands", "privacy": {"title": "Privacybeleid", "updated": "Laatst bijgewerkt: 16 juli 2026", "intro": "Warranta is een privacygerichte kluis voor je bonnen, garanties en retourtermijnen. Ze is zo gebouwd dat alles wat je toevoegt op je apparaat blijft. Dit beleid legt in gewone taal uit welke gegevens erbij betrokken zijn en hoe daarmee wordt omgegaan.", "sections": [{"h": "Gegevens die we verzamelen", "p": "Geen. Warranta vereist geen account en verzamelt, verzendt, verkoopt of deelt je persoonsgegevens niet. Je items, foto's, documenten, prijzen en notities verlaten je apparaat nooit, behalve binnen de back-up van je eigen apparaat (zie «Opslag en back-up»)."}, {"h": "Verwerking op het apparaat", "p": "Wanneer je een bon of garantie scant, wordt de tekst gelezen en worden de velden ingevuld met behulp van Apple's Vision-framework en de intelligentie op het apparaat. De afbeelding en de bijbehorende tekst worden volledig op je iPhone verwerkt en worden nooit naar ons of naar derden geüpload."}, {"h": "Netwerkgebruik", "p": "De enige netwerkactiviteit vindt plaats met Apple's App Store, voor aankopen en abonnementen. Als je Warranta Pro koopt, kan een optionele registratie één anonieme Apple-transactie-identificatie verzenden, zodat je abonnement kan worden herkend — deze bevat geen naam, e-mailadres of inhoud van items. Warranta bevat geen enkele SDK voor analyse, reclame of tracking en toont geen advertenties."}, {"h": "Machtigingen", "p": "Warranta kan toegang vragen tot de Camera (om een bon of garantie te fotograferen), de Fotobibliotheek (om een bestaande afbeelding te kiezen) en Meldingen (om je eraan te herinneren voordat een garantie of retourtermijn verloopt). Elke machtiging is optioneel, wordt alleen gevraagd wanneer nodig en wordt uitsluitend voor het genoemde doel gebruikt."}, {"h": "Opslag en back-up", "p": "Je gegevens worden lokaal op je apparaat opgeslagen. Als je de iCloud-apparaatback-up hebt ingeschakeld, worden je Warranta-gegevens opgenomen in die versleutelde Apple-back-up onder je eigen Apple-account. Wij beheren geen servers waarop je inhoud staat en wij kunnen je gegevens niet zien."}, {"h": "Je rechten en controle", "p": "Jij hebt altijd de controle. Je kunt op elk moment elk item binnen de app bewerken of verwijderen, en het verwijderen van de app wist alle bijbehorende gegevens van je apparaat. Omdat wij je persoonsgegevens op geen enkele server bewaren, is er niets waartoe wij namens jou toegang kunnen krijgen, dat wij kunnen exporteren, corrigeren of wissen — de rechten onder de AVG, de UK GDPR en de CCPA/CPRA worden door het ontwerp vervuld."}, {"h": "Diensten van derden", "p": "De enige betrokken derde partij is Apple, die App Store-aankopen en -abonnementen verwerkt en de iCloud-back-up levert. Die interacties vallen onder Apple's eigen Privacybeleid op apple.com/legal/privacy. Warranta integreert geen andere diensten van derden, advertentienetwerken of gegevensmakelaars."}, {"h": "Gegevensbewaring", "p": "Je gegevens blijven op je apparaat staan zolang je ze bewaart en worden verwijderd wanneer je ze verwijdert of de app wist. Wij bewaren niets, omdat wij je inhoud überhaupt nooit ontvangen."}, {"h": "Internationale gebruikers", "p": "Omdat alle verwerking op je apparaat plaatsvindt, wordt je inhoud niet naar ons overgedragen of over grenzen heen verplaatst. Waar je Warranta ook gebruikt, je gegevens blijven bij jou."}, {"h": "Privacy van kinderen", "p": "Warranta is niet gericht op kinderen jonger dan 13 jaar en verzamelt van niemand persoonsgegevens, ook niet van kinderen."}, {"h": "Wijzigingen in dit beleid", "p": "We kunnen dit beleid van tijd tot tijd bijwerken. Wezenlijke wijzigingen worden op deze pagina geplaatst met een nieuwe datum van «laatst bijgewerkt»; je voortgezette gebruik na een update betekent dat je het herziene beleid aanvaardt."}, {"h": "Contact", "p": "Vragen over privacy? Mail naar mustafaagulden@gmail.com en we helpen je graag verder."}]}, "terms": {"title": "Servicevoorwaarden", "updated": "Laatst bijgewerkt: 16 juli 2026", "intro": "Deze Servicevoorwaarden («Voorwaarden») zijn van toepassing op je gebruik van de Warranta-app. Door Warranta te downloaden of te gebruiken, ga je akkoord met deze Voorwaarden. Als je niet akkoord gaat, gebruik de app dan niet.", "sections": [{"h": "De dienst", "p": "Warranta helpt je aankoopbewijzen te bewaren en garanties en retourtermijnen bij te houden. Het is uitsluitend een organisatiehulpmiddel: het verstrekt, verlengt, verzekert of honoreert geen enkele garantie, en de herinneringen worden naar beste vermogen geleverd en kunnen vertraagd of gemist worden om redenen buiten onze controle. Bevestig belangrijke data en voorwaarden altijd rechtstreeks bij de verkoper of fabrikant."}, {"h": "Geschiktheid", "p": "Je mag Warranta alleen gebruiken als je een bindende overeenkomst kunt aangaan onder het op jou toepasselijke recht en als je meerderjarig bent in je land, of als je de app gebruikt onder toezicht van een ouder of wettelijke voogd."}, {"h": "Licentie", "p": "Wij verlenen je een persoonlijke, niet-exclusieve, niet-overdraagbare, herroepbare licentie om Warranta te gebruiken voor je eigen persoonlijke, niet-commerciële doeleinden, met inachtneming van deze Voorwaarden en van Apple's Licensed Application End User License Agreement (de standaard-EULA op apple.com/legal/internet-services/itunes/dev/stdeula)."}, {"h": "Aanvaardbaar gebruik", "p": "Je stemt ermee in Warranta rechtmatig te gebruiken en deze niet door te verkopen, te verhuren of te herdistribueren, noch de broncode te kopiëren, te wijzigen, te reverse-engineeren of te proberen te extraheren, behalve voor zover het toepasselijke recht dit ondanks deze beperking uitdrukkelijk toestaat."}, {"h": "Abonnementen en aankopen", "p": "Warranta Pro wordt aangeboden als automatisch verlengende abonnementen en, waar beschikbaar, als eenmalige aankoop, alle verwerkt door de App Store. De betaling wordt in rekening gebracht op je Apple ID. Abonnementen worden automatisch verlengd tenzij ze minstens 24 uur voor het einde van de lopende periode worden opgezegd. Een eventuele gratis proefperiode wordt omgezet in een betaald abonnement tenzij deze vóór het einde wordt opgezegd. Je kunt beheren of opzeggen in de instellingen van je App Store-account. Prijzen kunnen per regio verschillen en worden vóór de aankoop getoond."}, {"h": "App Store-voorwaarden", "p": "Deze Voorwaarden gelden tussen jou en de ontwikkelaar van Warranta, niet Apple, en Apple is niet verantwoordelijk voor de app of de inhoud ervan. Apple is niet verplicht enig onderhoud of enige ondersteuning voor de app te bieden. Voor zover maximaal toegestaan door de wet heeft Apple geen enkele garantieverplichting, en zijn alle vorderingen, verliezen, aansprakelijkheden of kosten die aan de app kunnen worden toegeschreven de verantwoordelijkheid van de ontwikkelaar, niet die van Apple. Apple en haar dochterondernemingen zijn derde-begunstigden van deze Voorwaarden en kunnen deze tegen je afdwingen."}, {"h": "Afwijzing van garanties", "p": "Warranta wordt geleverd «zoals ze is» en «zoals beschikbaar», zonder enige vorm van garantie, expliciet of impliciet. Wij garanderen niet dat herinneringen op tijd worden bezorgd, dat gescande gegevens juist zijn, of dat de app ononderbroken of foutloos zal zijn."}, {"h": "Beperking van aansprakelijkheid", "p": "Voor zover maximaal toegestaan door de wet zijn wij niet aansprakelijk voor een gemiste garantie- of retourdeadline, verloren gegevens, of indirecte, incidentele, bijzondere of gevolgschade die voortvloeit uit je gebruik van Warranta. Niets in deze Voorwaarden beperkt of sluit aansprakelijkheid uit die niet kan worden beperkt of uitgesloten onder het dwingende recht van je land."}, {"h": "Intellectueel eigendom", "p": "Warranta, de naam, het ontwerp en de inhoud ervan zijn eigendom van de ontwikkelaar en beschermd door het toepasselijke recht inzake intellectueel eigendom. Je eigen items, foto's en documenten blijven volledig van jou."}, {"h": "Beëindiging", "p": "Deze licentie blijft van kracht tot ze wordt beëindigd. Ze eindigt automatisch als je deze Voorwaarden op wezenlijke wijze schendt, en je kunt ze op elk moment beëindigen door de app te verwijderen. Bepalingen die naar hun aard de beëindiging behoren te overleven — zoals de afwijzingen van garantie, de beperking van aansprakelijkheid en de bepalingen inzake intellectueel eigendom — blijven van toepassing."}, {"h": "Wijzigingen in deze voorwaarden", "p": "We kunnen deze Voorwaarden van tijd tot tijd bijwerken. Wezenlijke wijzigingen worden op deze pagina geplaatst met een nieuwe datum van «laatst bijgewerkt». Voortgezet gebruik van Warranta nadat de wijzigingen van kracht zijn geworden, betekent dat je de bijgewerkte Voorwaarden aanvaardt."}, {"h": "Toepasselijk recht", "p": "Deze Voorwaarden worden beheerst door het recht van de Republiek Türkiye, onverminderd eventuele dwingende consumentenbeschermingsrechten waarop je recht hebt onder het recht van je land van verblijf, die van toepassing blijven."}, {"h": "Contact", "p": "Vragen over deze Voorwaarden? Mail naar mustafaagulden@gmail.com."}]}}, "ja": {"lang": "ja", "name": "日本語", "privacy": {"title": "プライバシーポリシー", "updated": "最終更新日: 2026年7月16日", "intro": "Warranta は、レシート、保証書、返品期間を管理するためのプライバシー第一の保管庫です。追加したすべての情報がお客様のデバイス上に留まるよう設計されています。本ポリシーでは、どのようなデータが関係し、それがどのように扱われるかを平易な言葉で説明します。", "sections": [{"h": "収集するデータ", "p": "収集しません。Warranta はアカウントを必要とせず、お客様の個人データを収集、送信、販売、または共有することはありません。お客様のアイテム、写真、書類、価格、メモは、お客様自身のデバイスバックアップ内を除き、デバイスから外部に出ることはありません（「保存とバックアップ」をご参照ください）。"}, {"h": "オンデバイス処理", "p": "レシートや保証書をスキャンすると、Apple のオンデバイス Vision フレームワークとオンデバイスインテリジェンスを使用してテキストが読み取られ、各項目が入力されます。画像とそのテキストは完全にお客様の iPhone 上で処理され、当社やいかなる第三者にもアップロードされることはありません。"}, {"h": "ネットワークの使用", "p": "唯一のネットワーク通信は、購入およびサブスクリプションのための Apple の App Store とのものです。Warranta Pro をご購入いただいた場合、任意の登録により、サブスクリプションを認識できるように匿名の Apple トランザクション識別子が一度だけ送信されることがあります。これには氏名、メールアドレス、アイテムの内容は一切含まれません。Warranta には、いかなる種類の分析、広告、トラッキング SDK も含まれておらず、広告を表示することもありません。"}, {"h": "権限", "p": "Warranta は、カメラ（レシートや保証書を撮影するため）、写真ライブラリ（既存の画像を選択するため）、および通知（保証や返品期間が終了する前にお知らせするため）へのアクセスを求める場合があります。各権限は任意であり、必要な場合にのみ要求され、明示された目的のためだけに使用されます。"}, {"h": "保存とバックアップ", "p": "お客様のデータはデバイス上にローカルで保存されます。iCloud デバイスバックアップを有効にしている場合、Warranta のデータはお客様自身の Apple アカウントのもとで暗号化された Apple バックアップに含まれます。当社はお客様のコンテンツを保持するサーバーを一切運用しておらず、お客様のデータを見ることはできません。"}, {"h": "お客様の権利と管理", "p": "お客様は常に管理権を保持しています。アプリ内でいつでも任意のアイテムを編集または削除でき、アプリを削除するとデバイスからそのすべてのデータが削除されます。当社はいかなるサーバーにもお客様の個人データを保持していないため、当社がお客様に代わってアクセス、エクスポート、訂正、または消去するものはありません。GDPR、UK GDPR、および CCPA/CPRA に基づく権利は、設計上すでに満たされています。"}, {"h": "第三者サービス", "p": "関与する唯一の第三者は Apple であり、App Store の購入およびサブスクリプションを処理し、iCloud バックアップを提供します。これらのやり取りは、apple.com/legal/privacy にある Apple 独自のプライバシーポリシーに準拠します。Warranta は、その他の第三者サービス、広告ネットワーク、データブローカーを一切統合していません。"}, {"h": "データの保持", "p": "お客様のデータは、お客様が保持する限りデバイス上に残り、削除するかアプリを削除した時点で消去されます。当社はそもそもお客様のコンテンツを一切受け取らないため、何も保持しません。"}, {"h": "海外のユーザー", "p": "すべての処理はお客様のデバイス上で行われるため、お客様のコンテンツが当社に転送されたり、国境を越えて移動したりすることはありません。どこで Warranta をご利用いただいても、お客様のデータはお客様のもとに留まります。"}, {"h": "子どものプライバシー", "p": "Warranta は13歳未満の子どもを対象としておらず、子どもを含むいかなる人からも個人データを収集しません。"}, {"h": "本ポリシーの変更", "p": "当社は本ポリシーを随時更新する場合があります。重要な変更については、新しい「最終更新日」とともに本ページに掲載します。更新後も継続してご利用いただくことは、改訂されたポリシーに同意されたものとみなされます。"}, {"h": "お問い合わせ", "p": "プライバシーに関するご質問は、mustafaagulden@gmail.com までメールでお問い合わせください。喜んでお手伝いいたします。"}]}, "terms": {"title": "利用規約", "updated": "最終更新日: 2026年7月16日", "intro": "本利用規約（以下「本規約」）は、Warranta アプリのご利用について定めるものです。Warranta をダウンロードまたは利用することにより、お客様は本規約に同意したものとみなされます。同意されない場合は、本アプリをご利用にならないでください。", "sections": [{"h": "サービス", "p": "Warranta は、購入の証明を保存し、保証や返品期間を把握するのに役立ちます。これは整理のためのツールにすぎず、いかなる保証を提供、延長、引受、または履行するものではありません。また、そのリマインダーは最善の努力に基づいて提供されるものであり、当社の管理外の理由により遅延または欠落する場合があります。重要な日付や条件については、必ず販売者またはメーカーに直接ご確認ください。"}, {"h": "利用資格", "p": "お客様は、ご自身に適用される法律のもとで拘束力のある契約を締結できる場合、かつご自身の国において成人年齢に達している場合、または親権者もしくは法定後見人の監督のもとで本アプリを利用する場合にのみ、Warranta をご利用いただけます。"}, {"h": "ライセンス", "p": "当社は、本規約および Apple のライセンス適用アプリケーションエンドユーザーライセンス契約（apple.com/legal/internet-services/itunes/dev/stdeula にある標準 EULA）に従うことを条件として、お客様がご自身の個人的かつ非商業的な目的のために Warranta を利用するための、個人的、非独占的、譲渡不可、取消可能なライセンスを付与します。"}, {"h": "許容される利用", "p": "お客様は、Warranta を合法的に利用し、再販、貸与、再配布を行わないこと、また、適用法がこの制限にかかわらず明示的に許可する限定的な範囲を除き、そのソースコードを複製、改変、リバースエンジニアリング、または抽出しようとしないことに同意します。"}, {"h": "サブスクリプションと購入", "p": "Warranta Pro は、自動更新サブスクリプションとして、また利用可能な場合は買い切り購入として提供され、いずれも App Store によって処理されます。お支払いはお客様の Apple ID に請求されます。サブスクリプションは、現在の期間終了の少なくとも24時間前に解約されない限り、自動的に更新されます。無料トライアルは、終了前に解約されない限り有料サブスクリプションに移行します。管理または解約は App Store アカウント設定で行えます。価格は地域によって異なる場合があり、購入前に表示されます。"}, {"h": "App Store の規約", "p": "本規約は、お客様と Warranta の開発者との間のものであり、Apple との間のものではなく、Apple は本アプリまたはその内容について責任を負いません。Apple は本アプリのメンテナンスやサポートを提供する義務を負いません。法律で認められる最大限の範囲において、Apple はいかなる保証義務も負わず、本アプリに起因するいかなる請求、損失、責任、または費用も、Apple ではなく開発者の責任となります。Apple およびその子会社は本規約の第三受益者であり、お客様に対して本規約を行使することができます。"}, {"h": "保証の否認", "p": "Warranta は「現状のまま」および「利用可能な範囲で」提供され、明示または黙示を問わず、いかなる種類の保証もありません。当社は、リマインダーが時間通りに配信されること、スキャンされたデータが正確であること、またはアプリが中断なくエラーなく動作することを保証しません。"}, {"h": "責任の制限", "p": "法律で認められる最大限の範囲において、当社は、保証や返品の期限の逸失、データの損失、または Warranta のご利用に起因する間接的、付随的、特別、もしくは結果的損害について責任を負いません。本規約のいかなる規定も、お客様の国の強行法規のもとで制限または除外できない責任を制限または除外するものではありません。"}, {"h": "知的財産", "p": "Warranta、その名称、デザイン、および内容は開発者に帰属し、適用される知的財産法によって保護されています。お客様ご自身のアイテム、写真、書類は、完全にお客様のものです。"}, {"h": "終了", "p": "本ライセンスは終了するまで継続します。お客様が本規約に重大な違反をした場合は自動的に終了し、お客様はアプリをアンインストールすることによりいつでも終了できます。免責事項、責任の制限、知的財産に関する条項など、その性質上終了後も存続すべき規定は、引き続き適用されます。"}, {"h": "本規約の変更", "p": "当社は本規約を随時更新する場合があります。重要な変更については、新しい「最終更新日」とともに本ページに掲載します。変更の発効後も継続して Warranta をご利用いただくことは、更新された規約に同意されたものとみなされます。"}, {"h": "準拠法", "p": "本規約は、トルコ共和国の法律に準拠します。ただし、お客様の居住国の法律のもとでお客様に付与される強行的な消費者保護の権利を妨げるものではなく、それらは引き続き適用されます。"}, {"h": "お問い合わせ", "p": "本規約に関するご質問は、mustafaagulden@gmail.com までメールでお問い合わせください。"}]}}, "ko": {"lang": "ko", "name": "한국어", "privacy": {"title": "개인정보 처리방침", "updated": "최종 업데이트: 2026년 7월 16일", "intro": "Warranta는 영수증, 보증서, 반품 기간을 위한 개인정보 보호 우선의 보관함입니다. 추가하는 모든 정보가 사용자의 기기 안에 머무르도록 설계되었습니다. 본 방침은 어떤 데이터가 관련되고 그것이 어떻게 처리되는지를 쉬운 언어로 설명합니다.", "sections": [{"h": "수집하는 데이터", "p": "없습니다. Warranta는 계정을 요구하지 않으며 사용자의 개인정보를 수집, 전송, 판매 또는 공유하지 않습니다. 사용자의 항목, 사진, 문서, 가격 및 메모는 사용자 자신의 기기 백업 내부를 제외하고는 기기를 벗어나지 않습니다(“저장 및 백업” 참조)."}, {"h": "온디바이스 처리", "p": "영수증이나 보증서를 스캔하면 Apple의 온디바이스 Vision 프레임워크와 온디바이스 인텔리전스를 사용하여 텍스트가 읽히고 항목이 입력됩니다. 이미지와 해당 텍스트는 전적으로 사용자의 iPhone에서 처리되며, 당사나 제3자에게 업로드되지 않습니다."}, {"h": "네트워크 사용", "p": "유일한 네트워크 활동은 구매 및 구독을 위한 Apple의 App Store와의 통신입니다. Warranta Pro를 구매하시는 경우, 구독을 인식할 수 있도록 선택적 등록을 통해 익명의 Apple 거래 식별자가 한 번만 전송될 수 있으며, 여기에는 이름, 이메일 또는 항목 내용이 포함되지 않습니다. Warranta에는 어떠한 종류의 분석, 광고, 추적 SDK도 포함되어 있지 않으며 광고를 표시하지 않습니다."}, {"h": "권한", "p": "Warranta는 카메라(영수증이나 보증서를 촬영하기 위해), 사진 보관함(기존 이미지를 선택하기 위해), 알림(보증 또는 반품 기간이 만료되기 전에 알려드리기 위해)에 대한 권한을 요청할 수 있습니다. 각 권한은 선택 사항이며, 필요한 경우에만 요청되고, 명시된 목적으로만 사용됩니다."}, {"h": "저장 및 백업", "p": "사용자의 데이터는 기기에 로컬로 저장됩니다. iCloud 기기 백업을 활성화한 경우, Warranta 데이터는 사용자 본인의 Apple 계정 하에 암호화된 Apple 백업에 포함됩니다. 당사는 사용자의 콘텐츠를 보유하는 서버를 운영하지 않으며, 사용자의 데이터를 볼 수 없습니다."}, {"h": "사용자의 권리 및 관리", "p": "사용자는 항상 통제권을 가집니다. 앱 내에서 언제든지 모든 항목을 편집하거나 삭제할 수 있으며, 앱을 삭제하면 기기에서 모든 데이터가 제거됩니다. 당사는 어떠한 서버에도 사용자의 개인정보를 보유하지 않으므로, 당사가 사용자를 대신하여 접근, 내보내기, 정정 또는 삭제할 것이 없습니다. GDPR, UK GDPR 및 CCPA/CPRA에 따른 권리는 설계상 이미 충족됩니다."}, {"h": "제3자 서비스", "p": "관련된 유일한 제3자는 Apple이며, App Store 구매 및 구독을 처리하고 iCloud 백업을 제공합니다. 이러한 상호작용은 apple.com/legal/privacy에 있는 Apple 자체의 개인정보 처리방침의 적용을 받습니다. Warranta는 다른 어떠한 제3자 서비스, 광고 네트워크 또는 데이터 브로커도 통합하지 않습니다."}, {"h": "데이터 보존", "p": "사용자의 데이터는 사용자가 보관하는 한 기기에 남아 있으며, 사용자가 삭제하거나 앱을 제거하면 삭제됩니다. 당사는 애초에 사용자의 콘텐츠를 전혀 받지 않으므로 아무것도 보존하지 않습니다."}, {"h": "해외 사용자", "p": "모든 처리가 사용자의 기기에서 이루어지므로, 사용자의 콘텐츠는 당사에 전송되거나 국경을 넘어 이동되지 않습니다. 어디에서 Warranta를 사용하든, 사용자의 데이터는 사용자와 함께 머무릅니다."}, {"h": "아동의 개인정보", "p": "Warranta는 13세 미만의 아동을 대상으로 하지 않으며, 아동을 포함한 누구로부터도 개인정보를 수집하지 않습니다."}, {"h": "본 방침의 변경", "p": "당사는 본 방침을 수시로 업데이트할 수 있습니다. 중요한 변경 사항은 새로운 “최종 업데이트” 날짜와 함께 본 페이지에 게시됩니다. 업데이트 이후에도 계속 사용하시는 것은 개정된 방침에 동의하시는 것으로 간주됩니다."}, {"h": "문의", "p": "개인정보에 관한 문의가 있으신가요? mustafaagulden@gmail.com으로 이메일을 보내주시면 기꺼이 도와드리겠습니다."}]}, "terms": {"title": "서비스 이용약관", "updated": "최종 업데이트: 2026년 7월 16일", "intro": "본 서비스 이용약관(이하 “약관”)은 Warranta 앱의 이용을 규율합니다. Warranta를 다운로드하거나 이용함으로써 사용자는 본 약관에 동의하는 것으로 간주됩니다. 동의하지 않으시는 경우 본 앱을 이용하지 마십시오.", "sections": [{"h": "서비스", "p": "Warranta는 구매 증빙을 저장하고 보증 및 반품 기간을 관리하는 데 도움을 줍니다. 이는 정리 도구일 뿐이며, 어떠한 보증도 제공, 연장, 인수 또는 이행하지 않습니다. 또한 그 알림은 최선의 노력을 기반으로 제공되며 당사의 통제를 벗어난 이유로 지연되거나 누락될 수 있습니다. 중요한 날짜와 조건은 항상 판매자 또는 제조업체에 직접 확인하시기 바랍니다."}, {"h": "이용 자격", "p": "사용자는 자신에게 적용되는 법률에 따라 구속력 있는 계약을 체결할 수 있고, 자신의 국가에서 성년에 도달했거나 부모 또는 법적 보호자의 감독하에 본 앱을 이용하는 경우에만 Warranta를 이용할 수 있습니다."}, {"h": "라이선스", "p": "당사는 본 약관 및 Apple의 라이선스 적용 애플리케이션 최종 사용자 라이선스 계약(apple.com/legal/internet-services/itunes/dev/stdeula에 있는 표준 EULA)을 조건으로, 사용자가 자신의 개인적이고 비상업적인 목적으로 Warranta를 이용할 수 있는 개인적, 비독점적, 양도 불가능하며 취소 가능한 라이선스를 부여합니다."}, {"h": "허용되는 이용", "p": "사용자는 Warranta를 합법적으로 이용하며, 이를 재판매, 임대 또는 재배포하지 않고, 적용 법률이 이 제한에도 불구하고 명시적으로 허용하는 제한된 범위를 제외하고는 그 소스 코드를 복제, 수정, 리버스 엔지니어링 또는 추출하려고 시도하지 않을 것에 동의합니다."}, {"h": "구독 및 구매", "p": "Warranta Pro는 자동 갱신 구독으로, 그리고 이용 가능한 경우 일회성 구매로 제공되며, 모두 App Store를 통해 처리됩니다. 결제는 사용자의 Apple ID로 청구됩니다. 구독은 현재 기간이 끝나기 최소 24시간 전에 취소하지 않는 한 자동으로 갱신됩니다. 무료 체험은 종료 전에 취소하지 않는 한 유료 구독으로 전환됩니다. App Store 계정 설정에서 관리하거나 취소할 수 있습니다. 가격은 지역에 따라 다를 수 있으며 구매 전에 표시됩니다."}, {"h": "App Store 약관", "p": "본 약관은 사용자와 Warranta 개발자 간의 것이며 Apple과의 것이 아니고, Apple은 본 앱이나 그 내용에 대해 책임을 지지 않습니다. Apple은 본 앱에 대한 유지관리나 지원을 제공할 의무가 없습니다. 법률이 허용하는 최대 범위 내에서 Apple은 어떠한 보증 의무도 지지 않으며, 본 앱에 기인하는 모든 청구, 손실, 책임 또는 비용은 Apple이 아닌 개발자의 책임입니다. Apple과 그 자회사는 본 약관의 제3수익자이며 사용자에 대해 본 약관을 집행할 수 있습니다."}, {"h": "보증의 부인", "p": "Warranta는 명시적이든 묵시적이든 어떠한 종류의 보증도 없이 “있는 그대로” 및 “이용 가능한 대로” 제공됩니다. 당사는 알림이 제때 전달되거나, 스캔된 데이터가 정확하거나, 앱이 중단이나 오류 없이 작동할 것을 보장하지 않습니다."}, {"h": "책임의 제한", "p": "법률이 허용하는 최대 범위 내에서, 당사는 누락된 보증 또는 반품 기한, 데이터 손실, 또는 Warranta 이용으로 인해 발생하는 간접적, 부수적, 특별 또는 결과적 손해에 대해 책임을 지지 않습니다. 본 약관의 어떠한 조항도 사용자 국가의 강행 법규에 따라 제한하거나 배제할 수 없는 책임을 제한하거나 배제하지 않습니다."}, {"h": "지적 재산", "p": "Warranta, 그 명칭, 디자인 및 내용은 개발자의 소유이며 적용되는 지적 재산법에 의해 보호됩니다. 사용자 본인의 항목, 사진 및 문서는 전적으로 사용자의 것으로 유지됩니다."}, {"h": "해지", "p": "본 라이선스는 해지될 때까지 계속됩니다. 사용자가 본 약관을 중대하게 위반하는 경우 자동으로 종료되며, 사용자는 앱을 삭제함으로써 언제든지 종료할 수 있습니다. 면책 조항, 책임의 제한, 지적 재산 조항 등 그 성질상 해지 후에도 존속되어야 하는 조항은 계속 적용됩니다."}, {"h": "본 약관의 변경", "p": "당사는 본 약관을 수시로 업데이트할 수 있습니다. 중요한 변경 사항은 새로운 “최종 업데이트” 날짜와 함께 본 페이지에 게시됩니다. 변경이 효력을 발생한 후에도 계속 Warranta를 이용하시는 것은 업데이트된 약관에 동의하시는 것으로 간주됩니다."}, {"h": "준거법", "p": "본 약관은 튀르키예 공화국의 법률에 따라 규율됩니다. 다만, 사용자의 거주 국가 법률에 따라 사용자에게 부여되는 강행적 소비자 보호 권리를 침해하지 않으며, 그러한 권리는 계속 적용됩니다."}, {"h": "문의", "p": "본 약관에 관한 문의가 있으신가요? mustafaagulden@gmail.com으로 이메일을 보내주십시오."}]}}, "zh": {"lang": "zh", "name": "简体中文", "privacy": {"title": "隐私政策", "updated": "最后更新：2026年7月16日", "intro": "Warranta 是一款注重隐私的保管库，用于存放您的收据、保修单和退货期限。它的设计确保您添加的所有内容都保留在您的设备上。本政策以通俗易懂的语言说明涉及哪些数据以及如何处理这些数据。", "sections": [{"h": "我们收集的数据", "p": "无。Warranta 无需账户，也不会收集、传输、出售或分享您的个人数据。您的项目、照片、文档、价格和备注绝不会离开您的设备，除非在您自己的设备备份内（见“存储与备份”）。"}, {"h": "设备端处理", "p": "当您扫描收据或保修单时，系统会使用 Apple 的设备端 Vision 框架和设备端智能读取文本并填写各字段。图像及其文本完全在您的 iPhone 上处理，绝不会上传给我们或任何第三方。"}, {"h": "网络使用", "p": "唯一的网络活动是与 Apple 的 App Store 进行购买和订阅。如果您购买 Warranta Pro，可选的注册可能会发送一个匿名的 Apple 交易标识符，以便识别您的订阅——其中不包含任何姓名、电子邮件或项目内容。Warranta 不包含任何形式的分析、广告或跟踪 SDK，也不显示任何广告。"}, {"h": "权限", "p": "Warranta 可能会请求相机权限（用于拍摄收据或保修单）、照片图库权限（用于选择现有图片）以及通知权限（用于在保修或退货期限到期前提醒您）。每项权限均为可选，仅在需要时请求，并且仅用于所述目的。"}, {"h": "存储与备份", "p": "您的数据在本地存储于您的设备上。如果您启用了 iCloud 设备备份，您的 Warranta 数据将包含在您自己 Apple 账户下的加密 Apple 备份中。我们不运营任何保存您内容的服务器，也无法看到您的数据。"}, {"h": "您的权利与控制", "p": "您始终掌握着控制权。您可以随时在应用内编辑或删除任何项目，删除应用即会从您的设备上移除其全部数据。由于我们不在任何服务器上保存您的个人数据，因此没有任何内容需要我们代您访问、导出、更正或删除——GDPR、英国 GDPR 以及 CCPA/CPRA 所规定的权利在设计上即已得到满足。"}, {"h": "第三方服务", "p": "唯一涉及的第三方是 Apple，它处理 App Store 的购买和订阅并提供 iCloud 备份。这些交互受 Apple 自身隐私政策的约束，详见 apple.com/legal/privacy。Warranta 不集成任何其他第三方服务、广告网络或数据经纪商。"}, {"h": "数据保留", "p": "只要您保留数据，它就会留在您的设备上，并在您删除数据或移除应用时被删除。我们不保留任何内容，因为我们从一开始就不会收到您的内容。"}, {"h": "国际用户", "p": "由于所有处理都在您的设备上进行，您的内容不会传输给我们，也不会跨境转移。无论您在何处使用 Warranta，您的数据都始终与您同在。"}, {"h": "儿童隐私", "p": "Warranta 并非面向 13 岁以下儿童，也不会从任何人（包括儿童）处收集个人数据。"}, {"h": "本政策的变更", "p": "我们可能会不时更新本政策。重大变更将连同新的“最后更新”日期发布在本页面上；您在更新后继续使用即表示您接受修订后的政策。"}, {"h": "联系我们", "p": "对隐私有疑问？请发送电子邮件至 mustafaagulden@gmail.com，我们将乐意为您提供帮助。"}]}, "terms": {"title": "服务条款", "updated": "最后更新：2026年7月16日", "intro": "本服务条款（“条款”）规范您对 Warranta 应用的使用。下载或使用 Warranta 即表示您同意本条款。如果您不同意，请勿使用本应用。", "sections": [{"h": "服务", "p": "Warranta 帮助您存放购买凭证并跟踪保修和退货期限。它仅是一款整理工具：它不提供、延长、承保或履行任何保修，其提醒基于尽力而为的原则提供，可能因我们无法控制的原因而延迟或遗漏。请务必直接向卖家或制造商确认重要的日期和条款。"}, {"h": "使用资格", "p": "只有在您能够根据适用于您的法律订立具有约束力的合同，并且您已达到所在国家的成年年龄，或在父母或法定监护人的监督下使用本应用时，您才可以使用 Warranta。"}, {"h": "许可", "p": "在遵守本条款以及 Apple 的授权应用程序最终用户许可协议（apple.com/legal/internet-services/itunes/dev/stdeula 上的标准 EULA）的前提下，我们授予您一项个人的、非独占的、不可转让的、可撤销的许可，供您为自己的个人非商业目的使用 Warranta。"}, {"h": "可接受的使用", "p": "您同意合法使用 Warranta，不得转售、出租或再分发它，也不得复制、修改、反向工程或试图提取其源代码，但适用法律在此限制之外明确允许的有限范围除外。"}, {"h": "订阅与购买", "p": "Warranta Pro 以自动续订订阅的形式提供，并在可用的情况下以一次性购买的形式提供，均由 App Store 处理。付款将从您的 Apple ID 扣除。除非在当前周期结束前至少 24 小时取消，订阅将自动续订。任何免费试用在结束前若未取消，将转为付费订阅。您可以在 App Store 账户设置中管理或取消。价格可能因地区而异，并会在购买前显示。"}, {"h": "App Store 条款", "p": "本条款是您与 Warranta 开发者之间的约定，而非与 Apple 之间的约定，Apple 对本应用及其内容不承担责任。Apple 没有义务为本应用提供任何维护或支持。在法律允许的最大范围内，Apple 不承担任何保修义务，任何归因于本应用的索赔、损失、责任或费用均由开发者而非 Apple 负责。Apple 及其子公司是本条款的第三方受益人，可对您强制执行本条款。"}, {"h": "保证免责声明", "p": "Warranta 按“现状”和“现有”提供，不附带任何明示或默示的任何形式的保证。我们不保证提醒会按时送达、扫描的数据准确无误，或应用运行不中断或无差错。"}, {"h": "责任限制", "p": "在法律允许的最大范围内，我们不对任何错过的保修或退货期限、数据丢失，或因您使用 Warranta 而产生的间接的、附带的、特殊的或后果性的损害承担责任。本条款中的任何内容均不限制或排除根据您所在国家的强制性法律不能限制或排除的责任。"}, {"h": "知识产权", "p": "Warranta 及其名称、设计和内容归开发者所有，并受适用的知识产权法保护。您自己的项目、照片和文档完全属于您。"}, {"h": "终止", "p": "本许可在终止之前持续有效。如果您在实质上违反本条款，本许可将自动终止，您也可以随时通过卸载应用来终止它。根据其性质应在终止后继续有效的条款——例如免责声明、责任限制和知识产权条款——将继续适用。"}, {"h": "本条款的变更", "p": "我们可能会不时更新本条款。重大变更将连同新的“最后更新”日期发布在本页面上。变更生效后您继续使用 Warranta 即表示您接受更新后的条款。"}, {"h": "适用法律", "p": "本条款受土耳其共和国法律管辖，但不影响您根据居住国法律所享有的任何强制性消费者保护权利，这些权利继续适用。"}, {"h": "联系我们", "p": "对本条款有疑问？请发送电子邮件至 mustafaagulden@gmail.com。"}]}}};
